"""Configuration checking and auto-fix logic"""

import logging

log = logging.getLogger(__name__)


class ConfigurationChecker:
    """Checks gateway configuration and optionally fixes issues.

    Monitors:
    - Public subnet settings
    - IP allocations (fixed assignments)
    """

    def __init__(self, gateway_client, config):
        """Initialize checker.

        Args:
            gateway_client: Authenticated ATTGateway instance
            config: Loaded Config instance
        """
        self.gateway = gateway_client
        self.config = config
        self.auto_fix = config.is_auto_fix_enabled()
        self.issues_found = []
        self.fixes_applied = []

    def check_public_subnet(self):
        """Check public subnet configuration.

        Returns:
            True if configuration is correct, False if issues found
        """
        expected = self.config.get_expected_public_subnet()

        if not expected:
            log.info("Public subnet check disabled")
            return True

        log.info("Checking public subnet configuration...")

        # Get current configuration
        dhcp_config = self.gateway.get_dhcp_config()
        current = dhcp_config['public_subnet']

        # Compare each field
        all_ok = True
        mismatches = {}

        for field, expected_value in expected.items():
            actual_value = current.get(field)

            if actual_value != expected_value:
                all_ok = False
                mismatches[field] = {
                    'expected': expected_value,
                    'actual': actual_value
                }
                log.warning(
                    f"  Public subnet mismatch: {field} = {actual_value} "
                    f"(expected: {expected_value})"
                )
            else:
                log.debug(f"  ✓ {field} = {actual_value}")

        if all_ok:
            log.info("✓ Public subnet configuration is correct")
            return True

        # Issues found
        issue_desc = f"Public subnet misconfigured: {len(mismatches)} field(s)"
        self.issues_found.append(issue_desc)

        if not self.auto_fix:
            log.warning("Auto-fix disabled - not correcting public subnet")
            return False

        # Apply fix
        log.warning("Applying public subnet fix...")
        try:
            success = self.gateway.update_dhcp_config(public_subnet=expected)

            if success:
                # Verify the fix
                dhcp_config_after = self.gateway.get_dhcp_config()
                current_after = dhcp_config_after['public_subnet']

                # Check if all fields match now
                verified = all(
                    current_after.get(field) == expected_value
                    for field, expected_value in expected.items()
                )

                if verified:
                    log.info("✓ Public subnet fix verified")
                    self.fixes_applied.append("Public subnet restored")
                    return True
                else:
                    log.error("✗ Public subnet fix did not take effect")
                    return False
            else:
                log.error("✗ Public subnet fix failed")
                return False

        except Exception as e:
            log.error(f"Error fixing public subnet: {e}")
            return False

    def check_ip_allocations(self):
        """Check IP allocation table for expected fixed allocations.

        Returns:
            True if all allocations are correct, False if issues found
        """
        expected_allocations = self.config.get_expected_ip_allocations()

        if not expected_allocations:
            log.info("IP allocation check disabled")
            return True

        log.info("Checking IP allocations...")

        # Get current allocations
        ipalloc_data = self.gateway.get_ip_allocations()
        current_allocations = ipalloc_data['allocations']

        # Log full allocation table
        log.debug("Current IP allocation table:")
        for mac, data in sorted(current_allocations.items()):
            log.debug(
                f"  {data['ip']:15s}  {mac:17s}  {data['status']:7s}  {data['allocation_type']}"
            )

        # Check each expected allocation
        all_ok = True
        missing_allocations = []

        for mac, expected_ip in expected_allocations.items():
            mac_lower = mac.lower()

            if mac_lower in current_allocations:
                current = current_allocations[mac_lower]
                if current['allocation_type'] == 'Fixed Allocation':
                    log.debug(f"  ✓ {expected_ip} ({mac}) is Fixed Allocation")
                else:
                    all_ok = False
                    log.warning(
                        f"  ✗ {expected_ip} ({mac}) is {current['allocation_type']}, "
                        f"expected Fixed Allocation"
                    )
                    missing_allocations.append(mac)
            else:
                all_ok = False
                log.warning(f"  ✗ {expected_ip} ({mac}) not found in allocation table")
                missing_allocations.append(mac)

        if all_ok:
            log.info("✓ All IP allocations are correct")
            return True

        # Issues found
        issue_desc = f"IP allocations missing/incorrect: {len(missing_allocations)} device(s)"
        self.issues_found.append(issue_desc)

        if not self.auto_fix:
            log.warning("Auto-fix disabled - not correcting IP allocations")
            return False

        # Apply fixes
        log.warning(f"Fixing {len(missing_allocations)} IP allocation(s)...")
        fixes_succeeded = []
        fixes_failed = []

        for mac in missing_allocations:
            try:
                log.info(f"Allocating IP for {mac}...")
                success = self.gateway.allocate_ip(mac)

                if success:
                    fixes_succeeded.append(mac)
                else:
                    fixes_failed.append(mac)

            except Exception as e:
                log.error(f"Error allocating IP for {mac}: {e}")
                fixes_failed.append(mac)

        # Verify fixes
        if fixes_succeeded:
            ipalloc_data_after = self.gateway.get_ip_allocations()
            current_allocations_after = ipalloc_data_after['allocations']

            verified_count = 0
            for mac in fixes_succeeded:
                mac_lower = mac.lower()
                if (mac_lower in current_allocations_after and
                    current_allocations_after[mac_lower]['allocation_type'] == 'Fixed Allocation'):
                    verified_count += 1
                else:
                    log.warning(f"Allocation for {mac} not verified")

            if verified_count == len(fixes_succeeded):
                log.info(f"✓ All {verified_count} IP allocation fix(es) verified")
                self.fixes_applied.append(f"IP allocations fixed: {verified_count} device(s)")
            else:
                log.warning(
                    f"Only {verified_count}/{len(fixes_succeeded)} IP allocation fixes verified"
                )

        if fixes_failed:
            log.error(f"Failed to fix {len(fixes_failed)} IP allocation(s): {fixes_failed}")
            return False

        return len(fixes_succeeded) > 0

    def run_all_checks(self):
        """Run all configured checks.

        Returns:
            Exit code: 0 (all good), 1 (fixes applied), 2 (errors)
        """
        log.info("=" * 60)
        log.info("AT&T Gateway Configuration Check")
        log.info(f"Firmware Version: {self.gateway.firmware_version}")
        log.info(f"Handler: {self.gateway.handler.__class__.__name__}")
        log.info(f"Auto-fix: {'enabled' if self.auto_fix else 'disabled'}")
        log.info("=" * 60)

        results = []

        # Run public subnet check
        try:
            result = self.check_public_subnet()
            results.append(result)
        except Exception as e:
            log.error(f"Public subnet check failed with error: {e}")
            results.append(False)

        # Run IP allocation check
        try:
            result = self.check_ip_allocations()
            results.append(result)
        except Exception as e:
            log.error(f"IP allocation check failed with error: {e}")
            results.append(False)

        # Summary
        log.info("=" * 60)
        log.info("CHECK SUMMARY")
        log.info("=" * 60)

        if self.issues_found:
            log.warning(f"Issues found: {len(self.issues_found)}")
            for issue in self.issues_found:
                log.warning(f"  - {issue}")
        else:
            log.info("No issues found")

        if self.fixes_applied:
            log.warning(f"Fixes applied: {len(self.fixes_applied)}")
            for fix in self.fixes_applied:
                log.warning(f"  - {fix}")

        # Determine exit code
        if all(results):
            if self.fixes_applied:
                log.info("Exit code: 1 (fixes were applied successfully)")
                return 1
            else:
                log.info("Exit code: 0 (all checks passed)")
                return 0
        else:
            log.error("Exit code: 2 (some checks/fixes failed)")
            return 2
